INSERT OR IGNORE INTO messages VALUES('fe128647f8fe7198c42e732563767c58','917359961709@s.whatsapp.net','917359961709@s.whatsapp.net','Keval',replace('🔐 Security & stability\n\nCannot fix iframe blocking issues\n\nCannot control Content-Security-Policy (CSP)\n\nCannot whitelist Moodle ↔️ Typebot domains\n\nRisk of bot breaking after updates\n\n🔁 Data & automation\n\n❌ No automatic user data sync\n\n❌ Cannot pass secure user identifiers\n\n❌ No course-based tagging\n\n❌ No bot-completion triggers\n\n📊 Mautic integration\n\n❌ Cannot add Mautic tracking script globally\n\n❌ No event-based email automation\n\n❌ Cannot track student behavior site-wide\n\n❌ No reliable campaign triggers\n\n🔐 Authentication\n\n❌ No SSO (Single Sign-On)\n\n❌ Users must manually enter details\n\n❌ Cannot link Moodle account → Typebot session\n\n⚙️ Performance & control\n\n❌ No server-level caching\n\n❌ No monitoring & logs\n\n❌ No performance tuning\n\n❌ No advanced error handling\n\n🧩 Customization & future scale\n\n❌ Cannot build Moodle plugin\n\n❌ Limited extensibility\n\n❌ Hard to scale or standardize\n\n🟡 What still works with Admin-only\n\n(For clarity)\n\nEmbed Typebot in courses\n\nRun bots for students\n\nCollect responses inside Typebot\n\nBasic usage, manual processes\n\nSimple client-ready summary\n\nWith admin-only access, we can embed and run Typebot, but we miss server-level security control, user data sync, Mautic automation, SSO, and long-term stability.','\n',char(10)),1769580752,0,0,'2026-03-07 09:25:23');
