INSERT OR IGNORE INTO messages VALUES('44fb956fe7d16fcc6118ff04d6a5db8f','917359961709@s.whatsapp.net',NULL,'Matty','We also need to know exactly what data we''re going to use to be able to do the contact list and all that type of stuff that the salesperson is going to do. We can get either an AI scraper tool, or we can create a bot that can extract all of the data and information that we need and give that to the salesperson so that they can start selling and doing things right away. We also need to know that information, too.',1772696953,1,0,'2026-03-07 09:25:23');
INSERT OR IGNORE INTO messages VALUES('1908c3792dab4f704ce2810d7c639d0b','917359961709@s.whatsapp.net','917359961709@s.whatsapp.net','Keval',replace('Sales & Lead Generation Strategy\n\nAs discussed, our sales process will begin by collecting potential customer data from third-party lead generation platforms such as ZoomInfo, SignalHire, and Apollo.io. These tools will help us identify and gather relevant contact details for businesses within our target market.\n\nAll collected lead data will then be stored and organized in Zoho CRM. This will act as the central system for managing leads, tracking interactions, and maintaining structured customer information.\n\nOnce the data is organized in Zoho, we will run targeted email marketing campaigns using Mautic. These campaigns will include:\n\nIntroduction to our product/platform\n\nDemo videos explaining the features\n\nInformational content about the benefits of the system\n\nWhen recipients open the email or interact with the campaign, we will track engagement through the campaign analytics.\n\nIf a lead shows interest or submits an inquiry, the sales team will follow up directly via email or phone. During this stage, the salesperson will:\n\nUnderstand the client’s requirements\n\nProvide additional information about the platform\n\nSchedule a demo if required\n\nFinally, qualified leads will be guided to our platform where we will complete the onboarding and convert them into customers.','\n',char(10)),1772697249,0,0,'2026-03-07 09:25:23');
